SELECT version_description
FROM resolution_versions
WHERE resolution_id = 0 AND version_number = 2;

SELECT resolution_id, COUNT(*) AS version_count
FROM resolution_versions
GROUP BY resolution_id;

SELECT meeting_record_no, meeting_date
FROM meeting_records
WHERE committee_id = 1;

SELECT resolution_no, status
FROM resolutions
ORDER BY date DESC;

SELECT MIN(date) AS earliest_adopted_date
FROM resolutions
WHERE status = 'Adopted';
